def get_user_by_id(cursor, user_id):
    # VULNERABLE: SQL Injection via string formatting
    query = "SELECT * FROM users WHERE id = %s" % user_id
    return cursor.execute(query)

def get_user_by_id_safe(cursor, user_id):
    # SECURE: Using parameterized queries
    query = "SELECT * FROM users WHERE id = ?"
    return cursor.execute(query, (user_id,))

def load_config(request):
    # VULNERABLE: Unsafe YAML loading
    import yaml
    data = request.get_data()
    return yaml.load(data)

def load_config_safe(request):
    # SECURE: Using safe_load
    import yaml
    data = request.get_data()
    return yaml.safe_load(data)

def run_ping(request):
    # VULNERABLE: Command injection via shell=True
    import subprocess
    hostname = request.args.get('host')
    return subprocess.check_output(f"ping -c 1 {hostname}", shell=True)

def run_ping_safe(request):
    # SECURE: Avoiding shell=True and using argument list
    import subprocess
    hostname = request.args.get('host')
    return subprocess.check_output(["ping", "-c", "1", hostname])

def render_user_profile(request):
    # VULNERABLE: Reflected XSS
    from flask import render_template_string
    name = request.args.get('name', 'Guest')
    return render_template_string(f"<h1>Welcome {name}</h1>")

def render_user_profile_safe(request):
    # SECURE: Using standard render_template with auto-escaping
    from flask import render_template
    name = request.args.get('name', 'Guest')
    return render_template("profile.html", name=name)

def read_user_file_safe(request):
    # SECURE: Use abspath and check prefix
    import os
    base_dir = "/var/www/uploads"
    filename = request.args.get('file')
    filepath = os.path.abspath(os.path.join(base_dir, filename))
    if not filepath.startswith(os.path.abspath(base_dir)):
        return "Access Denied", 403
    with open(filepath, 'r') as f:
        return f.read()

def get_user_data(request, db):
    # VULNERABLE: IDOR - No ownership check
    user_id = request.args.get('id')
    return db.query("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()

def get_user_data_safe(request, db, current_user):
    # SECURE: ownership check enforced
    user_id = request.args.get('id')
    if user_id != current_user.id:
        return "Unauthorized", 403
    return db.query("SELECT * FROM users WHERE id = ?", (user_id,)).fetchone()

def hash_password(password):
    # VULNERABLE: Use of weak MD5 hash
    import hashlib
    return hashlib.md5(password.encode()).hexdigest()

def hash_password_safe(password):
    # SECURE: Use of strong bcrypt hashing
    import bcrypt
    return bcrypt.hashpw(password.encode(), bcrypt.gensalt())

def redirect_to_next(request):
    # VULNERABLE: Open Redirect
    from flask import redirect
    target = request.args.get('next')
    return redirect(target)

def redirect_to_next_safe(request):
    # SECURE: Validate redirect target domain
    from flask import redirect, url_for
    target = request.args.get('next')
    if target.startswith('/'):
        return redirect(target)
    return redirect(url_for('index'))
